INSERT INTO tools (name, slug, tagline, description, website_url, pricing_type, pricing_details, skill_level, has_api, platforms, features, integrations, docs_url, is_published, best_for, not_for, editorial_verdict, last_verified_at) VALUES
('Lex', 'lex-writing', 'AI-native writing editor for long-form content', 'Lex is a distraction-free writing editor with AI built in. Hit +++ to generate, ask questions about your draft, get title suggestions, and receive feedback — all inline without context-switching to a separate AI tool.', 'https://lex.page', 'freemium', '[{"plan":"Free","price":"$0","features":["Basic AI features"]},{"plan":"Pro","price":"$8/mo","features":["Unlimited AI","Collaboration","Export"]}]', 'beginner', false, '{web}', '{"Inline AI generation","Draft Q&A","Title suggestions","AI feedback","Markdown support","Version history","Export to docs","Collaboration","Focus mode"}', '{"Google Docs","Notion","WordPress"}', 'https://lex.page/help', true, '{"Long-form writers","Bloggers","Newsletter authors"}', '{"Short-form copywriting","Technical documentation"}', 'The cleanest AI writing experience — feels like Google Docs met GPT-4 and decided to be minimal about it.', now()),
('Scribe', 'scribe-how', 'Auto-generate step-by-step guides from screen recordings', 'Scribe watches you complete a process and automatically creates a step-by-step guide with screenshots, text instructions, and click annotations. Turn any workflow into sharable documentation instantly.', 'https://scribehow.com', 'freemium', '[{"plan":"Free","price":"$0","features":["Unlimited guides","Chrome extension"]},{"plan":"Pro","price":"$29/user/mo","features":["Desktop recorder","Custom branding","Analytics"]},{"plan":"Enterprise","price":"Custom","features":["SSO","API","Audit logs"]}]', 'beginner', false, '{web,desktop}', '{"Auto screenshot capture","Step-by-step generation","Click annotation","Custom branding","Guide sharing","Embeddable guides","Redaction tools","Analytics","PDF export"}', '{"Confluence","Notion","Zendesk","SharePoint","Slack","LMS platforms"}', 'https://scribehow.com/resources', true, '{"Operations teams documenting SOPs","Customer success creating help docs","HR onboarding workflows"}', '{"Creative process documentation"}', 'Genuinely magical for process documentation — what takes 30 minutes to write manually, Scribe does in 30 seconds.', now()),
('Tango', 'tango-us', 'AI-powered workflow documentation with screenshots', 'Tango captures your clicks and keystrokes to auto-generate beautiful how-to guides. Features AI-enriched descriptions, blur for sensitive data, and one-click sharing — no video recording needed.', 'https://tango.us', 'freemium', '[{"plan":"Free","price":"$0","features":["25 captures/user","Chrome extension"]},{"plan":"Pro","price":"$16/user/mo","features":["Unlimited captures","Custom branding"]},{"plan":"Enterprise","price":"Custom","features":["SSO","Analytics","API"]}]', 'beginner', false, '{web,desktop}', '{"Auto-capture workflows","AI descriptions","Sensitive data blur","Custom branding","Embed anywhere","PDF export","Team workspaces","Chrome extension","Desktop app"}', '{"Notion","Confluence","Slack","Google Drive","SharePoint"}', 'https://help.tango.us', true, '{"Teams creating internal documentation","Trainers building guides","Support teams writing help articles"}', '{"Complex multi-app workflows"}', 'Faster than Scribe for quick captures; the sensitive data blur is a nice touch for compliance-conscious teams.', now()),
('Otter AI', 'otter-ai-meeting', 'AI meeting assistant with real-time transcription', 'OtterPilot joins your meetings, transcribes in real-time, generates summaries, captures action items, and creates shareable notes — making every meeting searchable and actionable.', 'https://otter.ai', 'freemium', '[{"plan":"Basic","price":"$0","features":["300 min/mo","30 min/conversation"]},{"plan":"Pro","price":"$17/mo","features":["1,200 min/mo","90 min/conversation"]},{"plan":"Business","price":"$30/user/mo","features":["6,000 min/mo","4hr/conversation"]}]', 'beginner', false, '{web,mobile}', '{"Real-time transcription","Meeting summaries","Action item extraction","OtterPilot auto-join","Slide capture","Speaker identification","Search across meetings","Channels","Analytics"}', '{"Zoom","Google Meet","Microsoft Teams","Salesforce","HubSpot","Slack","Notion"}', 'https://help.otter.ai', true, '{"Sales teams recording calls","Journalists transcribing interviews","Teams wanting searchable meetings"}', '{"Offline-only meetings","Non-English-heavy meetings"}', 'The most popular meeting transcription tool; OtterPilot auto-join means you can actually focus on the conversation.', now()),
('Fireflies.ai', 'fireflies-meeting', 'AI notetaker that transcribes and analyzes meetings', 'Fireflies.ai automatically records, transcribes, and analyzes voice conversations. Its AI generates meeting summaries, tracks topics and sentiment, and integrates with 40+ apps to keep your team aligned.', 'https://fireflies.ai', 'freemium', '[{"plan":"Free","price":"$0","features":["800 min storage","Limited AI summaries"]},{"plan":"Pro","price":"$18/user/mo","features":["Unlimited storage","AI summaries"]},{"plan":"Business","price":"$29/user/mo","features":["Conversation intelligence","Sentiment"]}]', 'beginner', true, '{web,mobile}', '{"Auto-join meetings","Transcription","AI summaries","Topic tracking","Sentiment analysis","Action items","Soundbites","Channels","Analytics dashboard","AskFred AI"}', '{"Zoom","Google Meet","Teams","Slack","Salesforce","HubSpot","Notion","Asana","Zapier","Dialpad"}', 'https://docs.fireflies.ai', true, '{"Sales teams analyzing calls","Managers tracking meeting outcomes","Remote teams"}', '{"Highly confidential meetings"}', 'Stronger analytics than Otter; sentiment analysis and topic tracking make it the better choice for sales orgs.', now()),
('Notion AI', 'notion-ai-workspace', 'AI assistant built into your Notion workspace', 'Notion AI helps you write, edit, summarize, brainstorm, and translate — all within your Notion pages. Ask questions about your workspace, autofill databases, and generate content without leaving your notes.', 'https://notion.so/product/ai', 'paid', '[{"plan":"AI Add-on","price":"$10/member/mo","features":["All AI features","Q&A","Autofill","Writing tools"]}]', 'beginner', true, '{web,desktop,mobile}', '{"AI writing","Summarization","Translation","Q&A across workspace","Database autofill","Brainstorming","Tone adjustment","Custom AI blocks","Meeting notes","Action items"}', '{"Slack","Google Drive","GitHub","Figma","Jira","Linear","Confluence import"}', 'https://notion.so/help/guides/using-notion-ai', true, '{"Teams already using Notion","Knowledge workers","Project managers"}', '{"Teams not on Notion"}', 'Best AI if you already live in Notion — workspace Q&A alone justifies the cost for large teams.', now()),
('Clockwise', 'clockwise', 'AI calendar management that optimizes your schedule', 'Clockwise uses AI to automatically organize your calendar for maximum focus time. It resolves scheduling conflicts, creates flexible meetings, and protects deep work blocks — making your calendar work for you.', 'https://clockwise.com', 'freemium', '[{"plan":"Free","price":"$0","features":["1 calendar","Basic optimization"]},{"plan":"Teams","price":"$6.75/user/mo","features":["Unlimited calendars","Team analytics"]},{"plan":"Enterprise","price":"Custom","features":["SSO","Advanced analytics"]}]', 'beginner', false, '{web}', '{"AI scheduling","Focus time protection","Flexible meetings","Conflict resolution","Meeting-free days","Team analytics","Smart 1:1 scheduling","Calendar audit","Slack status sync"}', '{"Google Calendar","Slack","Zoom","Asana","Linear","Notion"}', 'https://docs.clockwise.com', true, '{"Teams with heavy meeting loads","Engineering managers","Anyone protecting focus time"}', '{"Freelancers with simple schedules"}', 'The best calendar AI; protecting focus time automatically is something every knowledge worker needs.', now())
INSERT INTO tools (name, slug, tagline, description, website_url, pricing_type, pricing_details, skill_level, has_api, platforms, features, integrations, docs_url, is_published, best_for, not_for, editorial_verdict, last_verified_at) VALUES
('Harvey AI', 'harvey-ai', 'AI legal assistant for law firms', 'Harvey uses AI trained on legal data to draft documents, analyze contracts, conduct research, and answer legal questions. Built for lawyers with security and confidentiality at its core.', 'https://harvey.ai', 'enterprise', '[{"plan":"Enterprise","price":"Custom","features":["Legal AI assistant","Contract analysis","Research","Document drafting"]}]', 'intermediate', true, '{web}', '{"Legal document drafting","Contract analysis","Legal research","Regulatory analysis","Due diligence","Case law search","Custom workflows","Audit trails","Enterprise security"}', '{"Microsoft Word","Document management systems","Legal practice management"}', 'https://harvey.ai/resources', true, '{"Law firms","Corporate legal departments","Legal professionals"}', '{"Non-legal use cases"}', 'The leading AI for legal; trained on legal-specific data so outputs are far more reliable than general-purpose AI.', now()),
('Spellbook', 'spellbook-legal', 'AI contract drafting and review tool', 'Spellbook by Rally reviews and drafts contracts using AI trained on legal data. It suggests clauses, flags unusual terms, and drafts new language — integrated directly into Microsoft Word.', 'https://spellbook.legal', 'paid', '[{"plan":"Starter","price":"$100/user/mo","features":["Contract review","Clause suggestions"]},{"plan":"Plus","price":"$200/user/mo","features":["Custom playbooks","Advanced drafting"]}]', 'intermediate', false, '{web,desktop}', '{"Contract review","Clause suggestion","Risk flagging","Language drafting","Playbook enforcement","Redlining","Term extraction","Version comparison","Word integration"}', '{"Microsoft Word","Google Docs","Document management systems"}', 'https://spellbook.legal/resources', true, '{"Contract attorneys","In-house legal teams","Procurement teams"}', '{"Litigation-focused work"}', 'Purpose-built for contract work; the Word integration means lawyers adopt it without changing their workflow.', now()),
('Luminance', 'luminance', 'AI platform for legal document review and analysis', 'Luminance uses AI to read and understand legal documents at superhuman speed. Automatically review contracts, detect anomalies, and negotiate deals — used by 600+ law firms globally.', 'https://luminance.com', 'enterprise', '[{"plan":"Enterprise","price":"Custom","features":["Document review","Anomaly detection","Deal negotiation","Autopilot"]}]', 'intermediate', true, '{web}', '{"Document review","Anomaly detection","Contract negotiation","Auto-redlining","60+ language support","Due diligence","Compliance review","Knowledge management","Autopilot mode"}', '{"Microsoft 365","iManage","NetDocuments","SharePoint"}', 'https://luminance.com/resources', true, '{"Law firms doing M&A due diligence","Corporate legal teams","Global firms with multilingual contracts"}', '{"Small solo practitioners"}', 'Best for high-volume document review; the anomaly detection catches things human reviewers miss under time pressure.', now()),
('Ironclad AI', 'ironclad-ai', 'AI-powered contract lifecycle management', 'Ironclad combines CLM with AI to automate contract workflows end-to-end. From intake to negotiation to execution and renewal — AI assists at every stage of the contract lifecycle.', 'https://ironcladapp.com', 'enterprise', '[{"plan":"Enterprise","price":"Custom","features":["Full CLM","AI Assist","Workflow automation","Repository"]}]', 'intermediate', true, '{web,api}', '{"Contract lifecycle management","AI-assisted drafting","Workflow automation","Repository search","Obligation tracking","Renewal management","Approval routing","Analytics","E-signatures"}', '{"Salesforce","Slack","Microsoft 365","Google Workspace","DocuSign","Workday","NetSuite"}', 'https://developer.ironcladapp.com', true, '{"Legal operations teams","Contract-heavy businesses","Procurement departments"}', '{"One-off contract needs"}', 'The best CLM platform with AI baked in; end-to-end contract automation that actually delivers on the promise.', now())
INSERT INTO tools (name, slug, tagline, description, website_url, pricing_type, pricing_details, skill_level, has_api, platforms, features, integrations, docs_url, is_published, best_for, not_for, editorial_verdict, last_verified_at) VALUES
('Qualtrics XM', 'qualtrics-ai', 'AI-powered experience management platform', 'Qualtrics uses AI to analyze customer, employee, product, and brand experiences at scale. AI-driven insights, predictive analytics, and automated actions help organizations improve every interaction.', 'https://qualtrics.com', 'enterprise', '[{"plan":"Enterprise","price":"Custom","features":["Survey AI","Text analytics","Predictive intelligence","Automated actions"]}]', 'intermediate', true, '{web,api}', '{"AI-powered surveys","Text analytics","Sentiment analysis","Predictive modeling","Automated workflows","Experience dashboards","Statistical analysis","Trend detection","Multi-channel feedback"}', '{"Salesforce","Slack","Zendesk","ServiceNow","Marketo","Adobe","SAP","Tableau"}', 'https://api.qualtrics.com', true, '{"Enterprise CX teams","HR measuring employee experience","Product teams gathering feedback"}', '{"Small businesses with simple survey needs"}', 'The gold standard for experience management; AI text analytics turns mountains of open-ended feedback into actionable insights.', now()),
('Medallia', 'medallia', 'AI-powered customer experience analytics', 'Medallia captures and analyzes experience signals from every customer interaction — surveys, social, speech, digital behavior — using AI to surface patterns and drive real-time action.', 'https://medallia.com', 'enterprise', '[{"plan":"Enterprise","price":"Custom","features":["Omnichannel capture","AI analytics","Real-time actions","Role-based dashboards"]}]', 'intermediate', true, '{web,api}', '{"Omnichannel signal capture","AI text analytics","Sentiment analysis","Theme detection","Journey analytics","Real-time alerts","Action management","Role-based views","Speech analytics"}', '{"Salesforce","ServiceNow","Adobe","Slack","Teams","Workday","Genesys"}', 'https://docs.medallia.com', true, '{"Enterprise CX programs","Contact center operations","Hospitality and retail"}', '{"Startups with limited feedback volume"}', 'Stronger than Qualtrics for real-time operational CX; speech analytics for contact centers is best-in-class.', now()),
('Forethought', 'forethought', 'AI for customer support automation', 'Forethought uses generative AI to automate customer support — intelligently triaging tickets, suggesting responses, resolving common issues, and routing complex ones to the right agent.', 'https://forethought.ai', 'enterprise', '[{"plan":"Enterprise","price":"Custom","features":["AI triage","Agent assist","Auto-resolve","Knowledge base AI"]}]', 'intermediate', true, '{web,api}', '{"AI ticket triage","Agent assist","Auto-resolve","Knowledge base search","Sentiment detection","Priority prediction","Workflow automation","Performance analytics","Multi-channel"}', '{"Zendesk","Salesforce","ServiceNow","Intercom","Freshdesk","Kustomer"}', 'https://forethought.ai/resources', true, '{"Support teams with high ticket volume","E-commerce customer service","SaaS support teams"}', '{"Low-volume support teams"}', 'Best AI triage system; accurately routes tickets and auto-resolves simple ones, letting agents focus on complex issues.', now()),
('Assembled', 'assembled', 'AI workforce management for support teams', 'Assembled uses AI to forecast support demand, optimize agent scheduling, and provide real-time queue management. Purpose-built for customer support operations at scale.', 'https://assembled.com', 'paid', '[{"plan":"Growth","price":"Custom","features":["Forecasting","Scheduling"]},{"plan":"Enterprise","price":"Custom","features":["Advanced AI","Custom integrations","SSO"]}]', 'intermediate', true, '{web,api}', '{"AI demand forecasting","Agent scheduling","Real-time monitoring","Queue management","Capacity planning","Performance analytics","Schedule adherence","Multi-channel staffing","Vendor management"}', '{"Zendesk","Salesforce","Intercom","Kustomer","Amazon Connect","Twilio"}', 'https://docs.assembled.com', true, '{"Support ops managers","BPO teams","Contact center workforce planners"}', '{"Small teams without scheduling complexity"}', 'The best WFM tool purpose-built for support; AI forecasting is significantly more accurate than spreadsheet-based planning.', now()),
('Yuma AI', 'yuma-ai', 'AI agent for e-commerce customer support', 'Yuma AI autonomously handles e-commerce customer tickets — order tracking, returns, exchanges, and product questions. It reads your store data and policies to give accurate, personalized responses.', 'https://yuma.ai', 'paid', '[{"plan":"Starter","price":"$350/mo","features":["500 tickets/mo","Shopify integration"]},{"plan":"Growth","price":"$750/mo","features":["2000 tickets/mo","All integrations"]}]', 'intermediate', true, '{web,api}', '{"Autonomous ticket resolution","Order management","Returns handling","Product recommendations","Policy enforcement","Multi-language","Tone customization","Escalation rules","Analytics"}', '{"Shopify","Gorgias","Zendesk","Klaviyo","Recharge","Loop Returns"}', 'https://docs.yuma.ai', true, '{"Shopify stores with high ticket volume","E-commerce brands","DTC companies"}', '{"Non-e-commerce support"}', 'Purpose-built for e-commerce support; deeply understands Shopify data so responses are accurate about orders, not generic.', now())
INSERT INTO tools (name, slug, tagline, description, website_url, pricing_type, pricing_details, skill_level, has_api, platforms, features, integrations, docs_url, is_published, best_for, not_for, editorial_verdict, last_verified_at) VALUES
('ThoughtSpot', 'thoughtspot', 'AI-powered search and analytics for business data', 'ThoughtSpot lets anyone search their data using natural language and get instant AI-generated visualizations. SpotIQ automatically surfaces anomalies and trends humans might miss.', 'https://thoughtspot.com', 'freemium', '[{"plan":"Free","price":"$0","features":["5 users","50K rows"]},{"plan":"Essentials","price":"$1,250/mo","features":["Unlimited users","100M rows"]},{"plan":"Enterprise","price":"Custom","features":["Unlimited data","SSO","Governance"]}]', 'beginner', true, '{web,api}', '{"Natural language search","AI-generated charts","SpotIQ anomaly detection","Embedded analytics","Liveboards","Data modeling","R/Python integration","Governance","Mobile"}', '{"Snowflake","BigQuery","Redshift","Databricks","Postgres","Salesforce","dbt"}', 'https://developers.thoughtspot.com', true, '{"Business analysts","Data teams enabling self-serve analytics","Product teams embedding analytics"}', '{"Data engineering pipelines"}', 'The best natural-language BI tool; non-technical users can genuinely ask questions and get accurate charts.', now()),
('Sigma Computing', 'sigma-computing', 'Cloud analytics platform with AI-powered insights', 'Sigma Computing brings the power of cloud data warehouses to a spreadsheet-like interface. AI assists with formula creation, anomaly detection, and natural language queries against live cloud data.', 'https://sigmacomputing.com', 'freemium', '[{"plan":"Free","price":"$0","features":["Unlimited viewers"]},{"plan":"Essential","price":"$25/user/mo","features":["Workbooks","Dashboards"]},{"plan":"Business","price":"$75/user/mo","features":["Governance","Embedding","API"]}]', 'intermediate', true, '{web,api}', '{"Spreadsheet-like interface","Live cloud data","AI formula assist","Natural language queries","Dashboards","Embedding","Version control","Governance","Input tables"}', '{"Snowflake","BigQuery","Redshift","Databricks","PostgreSQL","dbt"}', 'https://docs.sigmacomputing.com', true, '{"Analysts comfortable with spreadsheets","Finance teams","Data teams democratizing access"}', '{"Real-time streaming analytics"}', 'The spreadsheet interface is a genius move — analysts adopt it instantly because it feels like Excel, but queries cloud data live.', now()),
('Census', 'census', 'Reverse ETL and AI-powered data activation', 'Census syncs your cloud data warehouse to 200+ business tools. Use AI to build customer segments, personalize marketing, and activate your data where teams actually work — no engineering required.', 'https://getcensus.com', 'freemium', '[{"plan":"Free","price":"$0","features":["1 destination","10K records"]},{"plan":"Core","price":"$350/mo","features":["Unlimited destinations","1M records"]},{"plan":"Enterprise","price":"Custom","features":["Unlimited records","SSO","SLA"]}]', 'intermediate', true, '{web,api}', '{"Reverse ETL","AI audience builder","200+ integrations","Data validation","Incremental sync","dbt integration","Observability","Entity resolution","No-code segments"}', '{"Snowflake","BigQuery","Redshift","Databricks","Salesforce","HubSpot","Braze","Iterable","Google Ads","Facebook Ads"}', 'https://docs.getcensus.com', true, '{"Marketing ops teams","Data teams activating warehouse data","Growth engineers"}', '{"ETL/data ingestion (use Fivetran)"}', 'Essential if your data lives in a warehouse but your teams work in SaaS tools; AI audience builder makes segmentation accessible.', now()),
('Hightouch', 'hightouch', 'AI-powered customer data activation', 'Hightouch activates your data warehouse as a Customer Data Platform. Sync audiences, build AI-powered segments, and personalize every customer touchpoint — all powered by your existing cloud data.', 'https://hightouch.com', 'freemium', '[{"plan":"Free","price":"$0","features":["1 destination","1 model"]},{"plan":"Pro","price":"$350/mo","features":["Unlimited models","5 destinations"]},{"plan":"Enterprise","price":"Custom","features":["Unlimited everything","SSO"]}]', 'intermediate', true, '{web,api}', '{"Data activation","AI audience segmentation","Customer 360","Identity resolution","Match Booster","Personalization","A/B testing","Composable CDP","Event sync"}', '{"Snowflake","BigQuery","Databricks","Redshift","Salesforce","Google Ads","Meta Ads","Braze","Iterable","Klaviyo"}', 'https://hightouch.com/docs', true, '{"Marketing teams with warehouse data","Growth teams","Data-driven personalization"}', '{"Companies without a data warehouse"}', 'Neck and neck with Census; Hightouch edges ahead with Customer Studio making non-technical users truly self-serve.', now()),
('Hex', 'hex-data', 'Collaborative data science and analytics platform', 'Hex combines SQL, Python, and no-code in a collaborative notebook. AI assists with writing queries, generating visualizations, debugging code, and explaining results — making data work accessible to everyone.', 'https://hex.tech', 'freemium', '[{"plan":"Free","price":"$0","features":["Community access","Basic features"]},{"plan":"Professional","price":"$28/user/mo","features":["Scheduled runs","Git sync"]},{"plan":"Team","price":"$42/user/mo","features":["Collaboration","Version control"]}]', 'intermediate', true, '{web,api}', '{"SQL + Python notebooks","AI Magic","No-code charts","Scheduled reports","Git sync","App builder","Version control","Collaboration","Data connections","Parameters"}', '{"Snowflake","BigQuery","Redshift","PostgreSQL","Databricks","dbt","GitHub","Slack"}', 'https://learn.hex.tech', true, '{"Data teams doing analytics","Analysts writing SQL/Python","Teams building data apps"}', '{"Production ML pipelines"}', 'The best collaborative data notebook; Magic AI for SQL and Python genuinely accelerates data work for the whole team.', now())
INSERT INTO tools (name, slug, tagline, description, website_url, pricing_type, pricing_details, skill_level, has_api, platforms, features, integrations, docs_url, is_published, best_for, not_for, editorial_verdict, last_verified_at) VALUES
('Abridge', 'abridge', 'AI medical documentation from patient conversations', 'Abridge uses AI to automatically generate clinical documentation from doctor-patient conversations. It captures the nuances of medical encounters and produces structured notes in real-time.', 'https://abridge.com', 'enterprise', '[{"plan":"Enterprise","price":"Custom","features":["Real-time documentation","EHR integration","Clinical AI"]}]', 'intermediate', false, '{web,mobile}', '{"Real-time transcription","Clinical note generation","ICD-10 coding suggestions","Patient summaries","EHR integration","HIPAA compliant","Multi-specialty","Ambient listening","Quality monitoring"}', '{"Epic","Cerner","Athenahealth","MEDITECH"}', 'https://abridge.com/resources', true, '{"Physicians wanting to reduce documentation burden","Health systems","Ambulatory clinics"}', '{"Non-clinical documentation"}', 'Top-tier ambient clinical documentation; significantly reduces physician burnout by cutting documentation time by 75%.', now()),
('Nuance DAX', 'nuance-dax', 'AI clinical documentation assistant by Microsoft', 'Nuance Dragon Ambient eXperience (DAX) uses AI to automatically create clinical documentation from patient-physician conversations, integrated deeply with Microsoft health cloud and major EHR systems.', 'https://nuance.com/healthcare/ambient-clinical-intelligence.html', 'enterprise', '[{"plan":"Enterprise","price":"Custom","features":["Ambient documentation","EHR integration","Analytics"]}]', 'intermediate', false, '{web,mobile}', '{"Ambient documentation","Clinical note generation","EHR integration","Voice commands","Specialty models","HIPAA compliant","Analytics","Quality reporting","Microsoft Cloud integration"}', '{"Epic","Cerner","Athenahealth","Microsoft 365","Azure"}', 'https://nuance.com/healthcare/resources', true, '{"Large health systems","Microsoft-ecosystem hospitals","Multi-specialty practices"}', '{"Small independent clinics (consider Abridge)"}', 'The enterprise standard for ambient documentation; Microsoft backing means deep integration with health system infrastructure.', now()),
('Paige AI', 'paige-ai', 'AI-powered pathology diagnostics', 'Paige AI is the first FDA-approved AI platform for digital pathology. It assists pathologists in detecting cancer and other diseases from tissue slides with superhuman accuracy and speed.', 'https://paige.ai', 'enterprise', '[{"plan":"Enterprise","price":"Custom","features":["FDA-approved AI","Cancer detection","Digital pathology"]}]', 'advanced', true, '{web,api}', '{"Cancer detection","Digital pathology","FDA approved","Prostate cancer grading","Breast cancer detection","Whole slide imaging","Lab integration","Research tools","Clinical decision support"}', '{"Philips IntelliSite","Leica Aperio","Hamamatsu","Laboratory LIS systems"}', 'https://paige.ai/resources', true, '{"Pathology labs","Oncology centers","Academic medical centers"}', '{"Non-pathology clinical applications"}', 'First FDA-approved AI in pathology; genuinely improves diagnostic accuracy and speed for cancer detection.', now()),
('Recursion Pharmaceuticals', 'recursion-pharma', 'AI-driven drug discovery platform', 'Recursion combines experimental biology with AI to decode biology and advance new drug candidates. Their platform maps biological relationships at scale to identify novel therapeutics.', 'https://recursion.com', 'enterprise', '[{"plan":"Enterprise/Partnership","price":"Custom","features":["Drug discovery platform","Biological mapping","Target identification"]}]', 'advanced', true, '{web}', '{"AI drug discovery","Biological mapping","Phenomics","Target identification","Lead optimization","Clinical candidate selection","Multi-omics integration","Partnership programs","LOWE platform"}', '{"Lab automation systems","Cloud computing","Research databases"}', 'https://recursion.com/technology', true, '{"Pharmaceutical companies","Biotech firms","Drug discovery researchers"}', '{"Clinical-stage development"}', 'One of the most promising AI drug discovery platforms; massive biological dataset gives a unique competitive moat.', now()),
('Insitro', 'insitro', 'Machine learning for drug discovery and development', 'Insitro uses ML to predict clinical outcomes from cellular and patient data. Their approach combines high-throughput biology with machine learning to de-risk drug development.', 'https://insitro.com', 'enterprise', '[{"plan":"Partnership","price":"Custom","features":["ML drug discovery","Clinical prediction","Target validation"]}]', 'advanced', false, '{web}', '{"ML-driven drug discovery","Patient stratification","Biomarker discovery","Cell-based assays","Disease modeling","Clinical prediction","Target validation","High-throughput screening"}', '{"Lab automation","Cloud ML platforms","Clinical trial databases"}', 'https://insitro.com/technology', true, '{"Pharma companies seeking ML partnerships","Drug discovery organizations"}', '{"Non-pharmaceutical applications"}', 'Strong ML-first approach to drug discovery; partnerships with major pharma validate the technology.', now())
INSERT INTO tools (name, slug, tagline, description, website_url, pricing_type, pricing_details, skill_level, has_api, platforms, features, integrations, docs_url, is_published, best_for, not_for, editorial_verdict, last_verified_at) VALUES
('Gong', 'gong-ai', 'Revenue intelligence platform powered by AI', 'Gong captures and analyzes customer interactions across calls, emails, and web — using AI to surface deal insights, coach reps, and forecast revenue with unprecedented accuracy.', 'https://gong.io', 'enterprise', '[{"plan":"Enterprise","price":"Custom","features":["Revenue intelligence","Call recording","Deal insights","Forecasting"]}]', 'beginner', true, '{web,api}', '{"Call recording","AI deal insights","Revenue forecasting","Coaching recommendations","Pipeline analytics","Competitive intel","Talk pattern analysis","Initiative tracking","Reality-based forecasting"}', '{"Salesforce","HubSpot","Slack","Zoom","Microsoft Teams","Google Meet","Outreach","LinkedIn"}', 'https://docs.gong.io', true, '{"B2B sales teams","Revenue leaders","Sales enablement managers"}', '{"Transactional sales","Non-sales conversations"}', 'The category leader in revenue intelligence; reality-based forecasting alone justifies the investment for B2B orgs.', now()),
('Clari', 'clari-ai', 'AI revenue platform for pipeline and forecasting', 'Clari uses AI to give complete visibility into your revenue pipeline. Automatically capture buyer signals, predict deal outcomes, inspect pipeline health, and forecast with machine-learned confidence.', 'https://clari.com', 'enterprise', '[{"plan":"Enterprise","price":"Custom","features":["Revenue platform","AI forecasting","Pipeline inspection","Capture"]}]', 'intermediate', true, '{web,api}', '{"AI forecasting","Pipeline inspection","Deal scoring","Activity capture","Revenue analytics","CRM hygiene","Mutual action plans","Revenue cadence","Board-ready reports"}', '{"Salesforce","HubSpot","Microsoft Dynamics","Outreach","Gong","Slack","Zoom","Gmail","Outlook"}', 'https://clari.com/resources', true, '{"CROs and revenue leaders","Sales ops teams","Board reporting"}', '{"SMB sales teams"}', 'Best for executive-level revenue visibility; the forecasting accuracy is significantly better than CRM-native tools.', now()),
('ZoomInfo', 'zoominfo', 'AI-powered B2B data and intelligence platform', 'ZoomInfo provides the largest B2B contact and company database enhanced with AI intent signals, buyer behavior data, and automated outreach. Find, target, and engage your ideal customers with precision.', 'https://zoominfo.com', 'enterprise', '[{"plan":"Professional","price":"Custom","features":["Company search","Contact data"]},{"plan":"Advanced","price":"Custom","features":["Intent data","Website visitors"]},{"plan":"Elite","price":"Custom","features":["All features","Engagement"]}]', 'beginner', true, '{web,api}', '{"Contact database","Intent signals","Company data","Buyer behavior","Website visitor tracking","Automated outreach","Org charts","Technographics","Scoops (news triggers)","Conversation intelligence"}', '{"Salesforce","HubSpot","Outreach","SalesLoft","Marketo","Microsoft Dynamics","LinkedIn","Slack"}', 'https://developers.zoominfo.com', true, '{"Sales development teams","Marketing teams targeting accounts","Revenue ops"}', '{"B2C companies","Very small businesses"}', 'The dominant B2B data provider; intent signals are genuinely useful for knowing when prospects are in-market.', now()),
('Lavender Email', 'lavender-email', 'AI email coach for sales reps', 'Lavender analyzes and scores your sales emails in real-time, then suggests improvements based on what actually gets replies. It personalizes intros using prospect data and coaches reps to write better.', 'https://lavender.ai', 'freemium', '[{"plan":"Free","price":"$0","features":["5 emails/mo analyzed"]},{"plan":"Individual","price":"$29/mo","features":["Unlimited emails","All features"]},{"plan":"Team","price":"$49/user/mo","features":["Team analytics","Manager dashboard"]}]', 'beginner', false, '{web}', '{"Email scoring","AI suggestions","Personalization","Prospect research","GIF/meme finder","Mobile preview","Team analytics","A/B insights","Reply prediction","Writing coach"}', '{"Gmail","Outlook","Outreach","SalesLoft","HubSpot","Apollo","LinkedIn"}', 'https://lavender.ai/resources', true, '{"SDRs and BDRs","Sales teams wanting higher reply rates","Sales managers coaching reps"}', '{"Marketing email campaigns"}', 'The best AI email coach for sales; teams consistently see 2-3x improvement in reply rates after adoption.', now()),
('Seamless.AI', 'seamless-ai', 'AI-powered sales lead and contact finder', 'Seamless.AI uses AI to find verified contact information — emails, direct dials, and cell phones — for your ideal customers in real-time. Build targeted prospect lists at scale.', 'https://seamless.ai', 'freemium', '[{"plan":"Free","price":"$0","features":["50 credits"]},{"plan":"Basic","price":"$147/mo","features":["250 credits/mo"]},{"plan":"Pro","price":"Custom","features":["Unlimited credits","Buyer intent"]}]', 'beginner', false, '{web}', '{"Contact search","Real-time verification","Direct dials","Chrome extension","List building","Buyer intent","Autopilot","Job changes","Data enrichment","Export"}', '{"Salesforce","HubSpot","Outreach","SalesLoft","LinkedIn","Pipedrive","Zoho"}', 'https://seamless.ai/resources', true, '{"SDRs building prospect lists","Recruiters finding candidates","Sales teams needing direct dials"}', '{"Enterprise accounts (use ZoomInfo)"}', 'Best for individual reps who need direct dials fast; less comprehensive than ZoomInfo but significantly more affordable.', now())
INSERT INTO tools (name, slug, tagline, description, website_url, pricing_type, pricing_details, skill_level, has_api, platforms, features, integrations, docs_url, is_published, best_for, not_for, editorial_verdict, last_verified_at) VALUES
('FourKites', 'fourkites', 'AI-powered supply chain visibility platform', 'FourKites provides real-time supply chain visibility using AI and ML. Track shipments across modes, predict ETAs, detect disruptions before they happen, and optimize logistics operations at scale.', 'https://fourkites.com', 'enterprise', '[{"plan":"Enterprise","price":"Custom","features":["Real-time tracking","AI predictions","Visibility platform"]}]', 'intermediate', true, '{web,api,mobile}', '{"Real-time shipment tracking","AI ETA prediction","Disruption detection","Multi-modal visibility","Yard management","Appointment scheduling","Carbon tracking","Network analytics","Control tower"}', '{"SAP","Oracle","Blue Yonder","Manhattan","Descartes","ERP systems","TMS platforms"}', 'https://docs.fourkites.com', true, '{"Shippers managing complex logistics","3PLs","Supply chain leaders"}', '{"Small local delivery operations"}', 'Category leader in supply chain visibility; AI predictions give 15-20min ETA accuracy that transforms logistics planning.', now()),
('project44', 'project44', 'AI supply chain visibility and analytics', 'project44 connects shippers, carriers, and logistics providers on a single visibility platform. AI-powered tracking, analytics, and exception management across ocean, air, truck, and rail.', 'https://project44.com', 'enterprise', '[{"plan":"Enterprise","price":"Custom","features":["Visibility platform","AI analytics","Exception management"]}]', 'intermediate', true, '{web,api}', '{"Multi-modal tracking","AI exception management","Predictive analytics","Carrier connectivity","Carbon calculations","Dwell time analysis","Network optimization","API platform","Reports"}', '{"SAP","Oracle","Blue Yonder","Manhattan","Kinaxis","Descartes","Coupa"}', 'https://developers.project44.com', true, '{"Enterprise shippers","Global logistics teams","Carrier management"}', '{"Last-mile delivery tracking"}', 'Strongest carrier network; the breadth of multimodal coverage makes it the go-to for global supply chain visibility.', now()),
('Coupa AI', 'coupa-ai', 'AI-powered business spend management', 'Coupa uses AI to optimize procurement, invoicing, and spend management. Community intelligence from $6T+ in cumulative spend powers recommendations that save money and reduce risk.', 'https://coupa.com', 'enterprise', '[{"plan":"Enterprise","price":"Custom","features":["Procurement","Invoicing","Spend analytics","AI recommendations"]}]', 'intermediate', true, '{web,api}', '{"AI spend analytics","Procurement automation","Invoice management","Community intelligence","Supplier risk scoring","Contract management","Budgeting","Savings tracking","Sustainability scoring"}', '{"SAP","Oracle","NetSuite","Workday","Salesforce","ERP systems"}', 'https://compass.coupa.com', true, '{"Procurement teams","Finance operations","Enterprise spend management"}', '{"Small business purchasing"}', 'The community intelligence from $6T in spend data is an unmatched competitive advantage for sourcing recommendations.', now()),
('Kinaxis', 'kinaxis', 'AI-powered supply chain planning and orchestration', 'Kinaxis RapidResponse uses AI for concurrent supply chain planning — demand, supply, inventory, and S&OP in a single platform. What-if scenarios run in seconds, not days.', 'https://kinaxis.com', 'enterprise', '[{"plan":"Enterprise","price":"Custom","features":["Supply chain planning","AI/ML","What-if scenarios","S&OP"]}]', 'advanced', true, '{web,api}', '{"Concurrent planning","AI/ML forecasting","What-if scenarios","Demand planning","Supply planning","Inventory optimization","S&OP","Control tower","Scenario comparison","Exception management"}', '{"SAP","Oracle","Microsoft Dynamics","Salesforce","Blue Yonder","Manhattan"}', 'https://kinaxis.com/resources', true, '{"Supply chain planners","S&OP leaders","Manufacturing planning teams"}', '{"Warehouse management"}', 'Best for concurrent planning — running what-if scenarios in seconds instead of days genuinely changes how planning teams work.', now())
INSERT INTO tools (name, slug, tagline, description, website_url, pricing_type, pricing_details, skill_level, has_api, platforms, features, integrations, docs_url, is_published, best_for, not_for, editorial_verdict, last_verified_at) VALUES
('Wiz', 'wiz', 'AI-powered cloud security platform', 'Wiz provides agentless cloud security with AI-driven risk prioritization. Scan your entire cloud environment in minutes, identify toxic risk combinations, and remediate — without deploying agents.', 'https://wiz.io', 'enterprise', '[{"plan":"Enterprise","price":"Custom","features":["Cloud security posture","Vulnerability management","Runtime protection"]}]', 'intermediate', true, '{web,api}', '{"Agentless scanning","Risk prioritization","Cloud posture management","Vulnerability management","Container security","IaC scanning","Secrets detection","Identity analysis","Attack path analysis","Runtime protection"}', '{"AWS","Azure","GCP","Kubernetes","Terraform","Jenkins","Jira","Slack","PagerDuty","ServiceNow"}', 'https://docs.wiz.io', true, '{"Cloud security teams","DevSecOps","CISOs needing cloud visibility"}', '{"On-premise only environments"}', 'The fastest-growing security startup for a reason; agentless scanning with risk graph visualization is genuinely revolutionary.', now()),
('Lacework', 'lacework', 'AI-powered cloud security and compliance', 'Lacework uses AI-driven anomaly detection to secure cloud environments. Polygraph technology builds behavioral baselines and automatically detects threats without writing rules.', 'https://lacework.com', 'enterprise', '[{"plan":"Enterprise","price":"Custom","features":["Cloud security","Anomaly detection","Compliance","Runtime protection"]}]', 'intermediate', true, '{web,api}', '{"Behavioral anomaly detection","Cloud compliance","Vulnerability management","Container security","IaC scanning","CI/CD integration","Alert contextualization","Composite alerts","Multi-cloud"}', '{"AWS","Azure","GCP","Kubernetes","Terraform","Jira","Slack","PagerDuty","Splunk","Sumo Logic"}', 'https://docs.lacework.net', true, '{"Security ops teams","Cloud compliance teams","DevSecOps practitioners"}', '{"Non-cloud environments"}', 'The behavioral detection approach catches threats that rule-based tools miss; fewer false positives means less alert fatigue.', now()),
('Vectra AI', 'vectra-ai', 'AI threat detection and response platform', 'Vectra AI uses patented AI to detect and respond to cyber attacks in real-time across cloud, network, and identity. Attack Signal Intelligence reduces alert noise by 80% and finds threats others miss.', 'https://vectra.ai', 'enterprise', '[{"plan":"Enterprise","price":"Custom","features":["NDR","Cloud detection","Identity threat detection","Managed response"]}]', 'advanced', true, '{web,api}', '{"Attack Signal Intelligence","Network detection","Cloud detection","Identity threat detection","Managed response (MDR)","Behavioral analytics","Threat prioritization","Forensics","SIEM enrichment"}', '{"CrowdStrike","SentinelOne","Splunk","Microsoft Sentinel","Palo Alto","AWS","Azure","M365"}', 'https://support.vectra.ai', true, '{"SOC teams","Enterprise security operations","Managed security providers"}', '{"Endpoint-only security needs"}', 'Best NDR platform; Attack Signal Intelligence genuinely reduces alert noise and surfaces real threats faster.', now()),
('Torq', 'torq', 'AI-powered security automation and orchestration', 'Torq is a no-code security automation platform that uses AI to build and run security workflows. Automate incident response, threat hunting, and security operations — 100x faster than traditional SOAR.', 'https://torq.io', 'enterprise', '[{"plan":"Enterprise","price":"Custom","features":["Security automation","AI workflows","Incident response","Integrations"]}]', 'intermediate', true, '{web,api}', '{"No-code automation","AI workflow builder","Incident response","Case management","Threat hunting","Compliance automation","Integration library","Parallel execution","Human-in-the-loop"}', '{"CrowdStrike","SentinelOne","Palo Alto","Splunk","ServiceNow","Jira","Slack","Okta","AWS","Azure"}', 'https://docs.torq.io', true, '{"Security operations teams","Incident responders","Security engineers automating workflows"}', '{"Non-security automation (use Tray/Zapier)"}', 'The modern replacement for legacy SOAR; no-code builder with AI makes security automation accessible to the whole team.', now())
INSERT INTO tools (name, slug, tagline, description, website_url, pricing_type, pricing_details, skill_level, has_api, platforms, features, integrations, docs_url, is_published, best_for, not_for, editorial_verdict, last_verified_at) VALUES
('Eightfold AI', 'eightfold-ai', 'AI talent intelligence platform', 'Eightfold AI uses deep learning to match talent with opportunities. From recruiting to retention, it analyzes skills and potential to help organizations hire, develop, and retain the right people.', 'https://eightfold.ai', 'enterprise', '[{"plan":"Enterprise","price":"Custom","features":["Talent acquisition","Talent management","Talent intelligence"]}]', 'intermediate', true, '{web,api}', '{"AI talent matching","Skills inference","Diversity analytics","Career pathing","Internal mobility","Candidate rediscovery","Pipeline analytics","Bias reduction","Talent marketplace"}', '{"Workday","SAP SuccessFactors","Oracle HCM","Greenhouse","Lever","iCIMS","LinkedIn","Indeed"}', 'https://eightfold.ai/resources', true, '{"Enterprise talent acquisition","HR leaders focused on skills-based hiring","Diversity recruiting"}', '{"Small businesses with simple hiring"}', 'The leading talent intelligence platform; skills inference reveals candidates traditional keyword matching misses entirely.', now()),
('Phenom', 'phenom', 'AI-powered talent experience platform', 'Phenom uses AI to personalize the talent experience for candidates, employees, recruiters, and managers. From career site to internal mobility, AI drives engagement and fit at every touchpoint.', 'https://phenom.com', 'enterprise', '[{"plan":"Enterprise","price":"Custom","features":["Career site AI","CRM","Internal mobility","Chatbot"]}]', 'intermediate', true, '{web,api}', '{"AI career site personalization","Talent CRM","Chatbot","Internal mobility","Employee experience","Referrals","Video assessments","Analytics","Diversity features","Gig marketplace"}', '{"Workday","SAP","Oracle","iCIMS","Greenhouse","Lever","LinkedIn","Indeed","Slack"}', 'https://phenom.com/resources', true, '{"Enterprise recruiting teams","Talent marketing","Internal mobility programs"}', '{"Staffing agencies"}', 'Best for full talent lifecycle; the AI-powered career site personalization measurably improves application rates.', now()),
('HireVue', 'hirevue', 'AI-powered video interviewing and assessments', 'HireVue uses AI to assess candidates through video interviews and game-based assessments. Structured evaluations, automated scheduling, and AI-driven insights help hiring teams make better, faster decisions.', 'https://hirevue.com', 'enterprise', '[{"plan":"Enterprise","price":"Custom","features":["Video interviews","AI assessments","Scheduling","Analytics"]}]', 'beginner', false, '{web,mobile}', '{"Video interviews","AI assessments","Game-based evaluations","Automated scheduling","Structured interviews","Candidate experience","Hiring team collaboration","Analytics","Bias auditing"}', '{"Workday","SAP","Oracle","iCIMS","Greenhouse","Lever","Outlook","Teams"}', 'https://hirevue.com/resources', true, '{"High-volume recruiting","Campus hiring","Enterprise talent acquisition"}', '{"Executive search","Creative roles"}', 'Best for high-volume hiring where consistent evaluation matters; game-based assessments are more engaging than traditional tests.', now()),
('Lattice', 'lattice-ai', 'AI-powered people management platform', 'Lattice uses AI to enhance performance management, engagement surveys, compensation, and career development. AI analyzes feedback patterns, suggests growth areas, and helps managers become better coaches.', 'https://lattice.com', 'paid', '[{"plan":"Performance","price":"$11/person/mo","features":["Reviews","Goals","1:1s"]},{"plan":"Suite","price":"$17/person/mo","features":["Engagement","Grow","Compensation"]}]', 'beginner', true, '{web,api}', '{"Performance reviews","Goal management","Engagement surveys","Compensation management","Career tracks","AI feedback analysis","1:1 agendas","Analytics","OKRs","Continuous feedback"}', '{"Slack","Microsoft Teams","Jira","BambooHR","Rippling","Workday","HRIS systems"}', 'https://developers.lattice.com', true, '{"People ops teams","Managers coaching direct reports","Growing companies building culture"}', '{"Payroll or HRIS replacement"}', 'The best modern people management platform; AI feedback analysis gives managers actionable coaching insights they would not find alone.', now())
INSERT INTO tools (name, slug, tagline, description, website_url, pricing_type, pricing_details, skill_level, has_api, platforms, features, integrations, docs_url, is_published, best_for, not_for, editorial_verdict, last_verified_at) VALUES
('Matterport', 'matterport', 'AI-powered 3D digital twin platform', 'Matterport creates photorealistic 3D digital twins of physical spaces. AI extracts measurements, generates floor plans, and creates immersive virtual tours — transforming how spaces are documented and marketed.', 'https://matterport.com', 'freemium', '[{"plan":"Free","price":"$0","features":["1 active space"]},{"plan":"Starter","price":"$12/mo","features":["5 spaces"]},{"plan":"Professional","price":"$32/mo","features":["25 spaces","MLS-ready"]}]', 'beginner', true, '{web,mobile,api}', '{"3D digital twins","AI measurements","Floor plans","Virtual tours","Dollhouse view","Property marketing","MLS integration","Schematic floor plans","Tags and notes","4K photography"}', '{"Zillow","Realtor.com","MLS systems","Google Street View","Airbnb","BoomTown"}', 'https://matterport.com/developers', true, '{"Real estate agents","Property managers","Architects and contractors"}', '{"Non-spatial applications"}', 'The category creator for 3D tours; AI floor plans and measurements save thousands in manual surveying costs.', now()),
('Entera', 'entera', 'AI-powered residential real estate investment platform', 'Entera uses AI to help investors find, evaluate, and acquire residential properties. Analyzes millions of properties using 200+ data points to surface optimal investment opportunities.', 'https://entera.ai', 'paid', '[{"plan":"Platform","price":"Custom","features":["AI property search","Portfolio analytics","Acquisition management"]}]', 'intermediate', false, '{web}', '{"AI property scoring","200+ data points","Portfolio optimization","Market analytics","Acquisition workflow","Comparable analysis","ROI forecasting","Risk assessment","Multi-market search"}', '{"MLS databases","County records","Zillow","Redfin","Property management systems"}', 'https://entera.ai/resources', true, '{"Residential real estate investors","SFR portfolio managers","Institutional buyers"}', '{"Owner-occupant home buyers"}', 'Best for serious residential investors; the 200+ data point scoring surfaces opportunities humans simply cannot find manually.', now()),
('Skyline AI', 'skyline-ai-proptech', 'AI-powered commercial real estate investment', 'Skyline AI (a JLL company) uses machine learning to analyze commercial real estate investment opportunities. Processes hundreds of data sources to predict property performance and identify undervalued assets.', 'https://skyline.ai', 'enterprise', '[{"plan":"Enterprise","price":"Custom","features":["CRE analytics","AI underwriting","Market predictions"]}]', 'advanced', true, '{web}', '{"AI property underwriting","Market prediction","Asset scoring","Risk analysis","Portfolio optimization","Due diligence automation","Data aggregation","Performance forecasting","Comparable analytics"}', '{"CoStar","CBRE","JLL platforms","CRM systems"}', 'https://skyline.ai/resources', true, '{"Institutional CRE investors","REITs","Commercial real estate funds"}', '{"Residential investors","Small landlords"}', 'Backed by JLL; the AI underwriting genuinely finds alpha in commercial real estate data that traditional analysis misses.', now()),
('Testfit', 'testfit', 'AI-powered building feasibility and site planning', 'Testfit uses AI to instantly generate optimal building configurations for real estate sites. Test feasibility, maximize unit counts, and evaluate financial returns — in minutes instead of weeks.', 'https://testfit.io', 'paid', '[{"plan":"Pro","price":"Custom","features":["AI site planning","Unit optimization","Financial analysis"]}]', 'intermediate', false, '{web}', '{"AI site planning","Building configuration","Unit count optimization","Parking optimization","Financial modeling","Zoning compliance","Solar analysis","Multi-scenario comparison","Export to CAD"}', '{"AutoCAD","Revit","SketchUp","Excel"}', 'https://testfit.io/resources', true, '{"Real estate developers","Architects evaluating sites","Multifamily investors"}', '{"Single-family home design"}', 'Revolutionary for multifamily feasibility; what takes architects weeks to test, Testfit does in minutes with better optimization.', now())
